import { ExternalTokenizer } from '@lezer/lr';

import { characterCodes } from '../character-codes.js';
import { JsonPathIdentifier } from '../parser.terms.js';

const { BACKSLASH } = characterCodes;

const disallowedJsonPathIdentifierChars = new RegExp(/[,()!<>="$:[\]~ .]/);

/** @internal */
export const jsonPathIdentifierTokenizer = new ExternalTokenizer(
  (inputStream, stack) => {
    if (stack.context.lastToken !== 'JsonPathBase' || inputStream.next === -1) {
      return;
    }

    const start = inputStream.pos;

    while (
      !disallowedJsonPathIdentifierChars.test(
        String.fromCharCode(inputStream.next),
      ) &&
      inputStream.next !== -1
    ) {
      // If the current character is a backslash (escape character), advance once
      // more to skip the escaped character.
      if (inputStream.next === BACKSLASH) {
        inputStream.advance();
      }

      // Move on to the next character.
      inputStream.advance();
    }

    if (inputStream.pos > start) {
      inputStream.acceptToken(JsonPathIdentifier);
    }
  },
);
